def get_character_info(chat_id):
    if chat_id in CHARACTER_MAP:
        info = CHARACTER_MAP[chat_id]
    else:
        info = {
            "character": FRIEND,
            "users_names": ["любимая", "любовь моя"],
            "users_gender": "female"  # Default gender
        }
    return info["character"], info["users_names"], info["users_gender"]

def format_character_prompt(character, users_names):
    names_str = ", ".join(users_names) if users_names else "не указаны"
    return f"Персонаж: {character}\nИмена пользователя: {names_str}."

def get_character(chat_id):
    character, users_names, users_gender = get_character_info(chat_id)
    return format_character_prompt(character, users_names), users_gender